import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 箜篌 } from '../bujian/sanmaya.js';
import { 手勢, 指寬 } from '../bujian/zhi.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛歌 = (bi) => 菩薩坐身(bi, {
    髻: '天髻',
    冠: '無',
    嚴先: true,
    臂(bi, 筆) {
        const { 骨, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 箜篌：斜抱當胸（弓形響胴在尊左，棹出尊右）
        箜篌(bi, 3.2, 35.2, 1.05);
        // 尊左臂：前臂橫入，拳把胴之下端
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [7.4, 40.2], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.35, 肘帽: true })));
        側拳(bi, 5.4, 39.8, -0.3, 1.06, -1);
        // 尊右臂：前臂上收，指就弦而彈（三指微張）
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-4.4, 37.7], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        {
            const s = 手勢(bi, -2.6, 36.6, 1.0);
            s.衣(() => {
                s.M(-1.6, 1.4);
                s.Qk(-0.5, 1.9, 0.6, 1.6);
                s.S(); // 掌背小丘
                for (const [i, 根a] of [-0.3, 0.45, 1.15].entries()) {
                    const 鏈 = s.指(根a, 1.1 - i * 0.15, -Math.PI / 2 + 0.75 + i * 0.14, [1.6 - i * 0.15, 1.15 - i * 0.1], [0, 0.3]);
                    s.畫(鏈, 指寬.根, 指寬.梢, { 紋: true });
                }
                const 拇 = s.指(-1.2, 1.2, -Math.PI / 2 + 1.15, [1.4, 1.1], [0, -0.25]);
                s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true });
            });
        }
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-5.8, 36.9, -5.1, 37.9, -5.7, 39.0], [-4.9, 36.7, -4.2, 37.7, -4.8, 38.8]], [-5.0, 37.8]);
            腕釧(bi, [[8.5, 39.2, 8.0, 40.3, 8.5, 41.5], [9.4, 39.4, 8.9, 40.5, 9.4, 41.7]], [9.1, 40.5]);
        });
    },
});
